async function o(){const t=await chrome.storage.local.get(["accessToken"]);if(t.accessToken)return t.accessToken;try{const e=await(await fetch("https://chrome-extension-errorlens.onrender.com/auth/guest",{method:"POST"})).json();if(e.guestToken)return await chrome.storage.local.set({accessToken:e.guestToken}),e.guestToken}catch(r){console.error("Failed to get guest token",r)}return""}async function s(t){if(!t)return!0;try{const e=await(await fetch("https://chrome-extension-errorlens.onrender.com/usage",{headers:{Authorization:`Bearer ${t}`}})).json();return e.remaining>0||e.plan!=="FREE"}catch(r){return console.error("Usage check failed",r),!0}}export{s as c,o as g};
